1320	
1321	  // Get the canonical use location for a (location, decl) pair.
1322	  // Decide whether the file expanding the macro or the file defining the macro
1323	  // should be held responsible for a use.
1324	  SourceLocation GetCanonicalUseLocation(SourceLocation use_loc,
1325	                                         const NamedDecl* decl) {
1326	    CHECK_(decl != nullptr) << ": Need a decl to compute use location";
1327	
1328	    // If we're not in a macro, just echo the use location.
1329	    if (!use_loc.isMacroID())
1330	      return use_loc;
1331	
1332	    VERRS(5) << "Trying to determine use location for '" << PrintableDecl(decl)
1333	             << "'\n";
1334	
1335	    SourceManager* sm = GlobalSourceManager();
1336	    SourceLocation spelling_loc = sm->getSpellingLoc(use_loc);
1337	    SourceLocation expansion_loc = sm->getExpansionLoc(use_loc);
1338	
1339	    // If the file defining the macro contains a forward decl, keep it around
1340	    // and treat it as a hint that the expansion loc is responsible for the
1341	    // symbol.
1342	    OptionalFileEntryRef macro_def_file = GetLocFileEntry(spelling_loc);
1343	    VERRS(5) << "Macro is defined in '" << GetFilePath(macro_def_file) << "'\n";
1344	
1345	    const NamedDecl* fwd_decl = nullptr;
1346	    for (const NamedDecl* redecl : GetTagRedecls(decl)) {
1347	      if (GetFileEntry(redecl) == macro_def_file && IsForwardDecl(redecl)) {
1348	        VERRS(5) << "Found fwd-decl hint at "
1349	                 << PrintableLoc(GetLocation(redecl)) << "\n";
1350	        fwd_decl = redecl;
1351	        break;
1352	      }
1353	    }
1354	
1355	    if (!fwd_decl) {
1356	      if (const auto* func_decl = dyn_cast<FunctionDecl>(decl)) {
1357	        if (const FunctionTemplateDecl* ft_decl =
1358	                func_decl->getPrimaryTemplate()) {
1359	          VERRS(5) << "No fwd-decl found, looking for function template decl\n";
1360	          for (const NamedDecl* redecl : ft_decl->redecls()) {
1361	            if (GetFileEntry(redecl) == macro_def_file) {
1362	              VERRS(5) << "Found function template at "
1363	                       << PrintableLoc(GetLocation(redecl)) << "\n";
1364	              fwd_decl = redecl;
1365	              break;
1366	            }
1367	          }
1368	        }
1369	      }
1370	    }
1371	
1372	    if (fwd_decl) {
1373	      // Make sure we keep that forward-declaration, even if it's probably
1374	      // unused in this file.
1375	      IwyuFileInfo* file_info = preprocessor_info().FileInfoFor(macro_def_file);
1376	      file_info->ReportForwardDeclareUse(
1377	          spelling_loc, fwd_decl, ComputeUseFlags(current_ast_node()), nullptr);
1378	    }
1379	
1380	    // Resolve the best use location based on our current knowledge.
1381	    //
1382	    // 1) If the use_loc is in <scratch space>, we assume it's formed by macro
1383	    //    argument concatenation, and attribute responsibility to the expansion
1384	    //    location.
1385	    // 2) If the macro definition file forward-declares the used decl, that's a
1386	    //    hint that it wants the expansion location to take responsibility.
1387	    //
1388	    // Otherwise, the spelling loc is responsible.
1389	    const char* side;
1390	    if (IsInScratchSpace(spelling_loc)) {
1391	      VERRS(5) << "Spelling location is in <scratch space>, presumably as a "
1392	               << "result of macro arg concatenation\n";
1393	      use_loc = expansion_loc;
1394	      side = "expansion";
1395	    } else if (StartsWith(PrintableLoc(spelling_loc), "<command line>")) {
1396	      VERRS(5) << "Spelling location is in <command line> (macro defined in "
1397	                  "command line), use expansion location instead\n";
1398	      use_loc = expansion_loc;
1399	      side = "expansion";
1400	    } else if (fwd_decl != nullptr) {
1401	      VERRS(5) << "Found a hint decl in macro definition file\n";
1402	      use_loc = expansion_loc;
1403	      side = "expansion";
1404	    } else {
1405	      use_loc = spelling_loc;
1406	      side = "spelling";
1407	    }
1408	
1409	    VERRS(4) << "Attributing use of '" << PrintableDecl(decl) << "' to " << side
1410	             << " location at " << PrintableLoc(use_loc) << "\n";
1411	
1412	    return use_loc;
1413	  }
1414	
1415	  // There are a few situations where iwyu is more restrictive than
1416	  // C++: where C++ allows a forward-declare but iwyu wants the full
1417	  // type.  One is in a typedef: if you write 'typedef Foo MyTypedef',
1418	  // iwyu says that you are responsible for #including "foo.h", but
1419	  // the language allows a forward-declare.  Another is for
1420	  // 'autocast': if your function has a parameter with a conversion
1421	  // (one-arg, not-explicit) constructor, iwyu requires that the
1422	  // function-author provides the full type of that parameter, but
1423	  // the language doesn't.  (It's ok with all callers providing the
1424	  // full type instead.)
1425	  //
1426	  // In each of these situations, we allow the user to say that iwyu
1427	  // should not require #includes for these underlying types, but
1428	  // allow forward-declares instead.  The author can do this by
1429	  // explicitly forward-declaring in the same file: for instance, they
1430	  // would do
1431	  //    class Foo; typedef Foo MyTypedef;   // can be on different lines :-)
1432	  //    class AutocastType; void MyFunc(AutocastType);   // but in same file
1433	  // If a definition- or declaration-site does this forward-declaring
1434	  // *and* does not directly #include the necessary file for Foo or
1435	  // AutocastType, we take that as a signal from the code-author that
1436	  // iwyu should relax its policies.  These functions calculate the
1437	  // types (which may have many component-types if it's a templated
1438	  // type) for which the code-author has made this decision.
1439	  bool CodeAuthorWantsJustAForwardDeclare(const Type* type,
1440	                                          SourceLocation use_loc) const {
1441	    const NamedDecl* decl = TypeToDeclAsWritten(type);
1442	    if (decl == nullptr)   // only class-types are candidates for returning true
1443	      return false;
1444	
1445	    // Sometimes a type points back to an implicit decl (e.g. a bultin type),
1446	    // and we can't do author-intent analysis without location information.
1447	    // Assume that it's not forward-declarable.
1448	    if (decl->isImplicit()) {
1449	      VERRS(5) << "Skipping forward-declare analysis for implicit decl: '"
1450	               << PrintableDecl(decl) << "'\n";
1451	      return false;
1452	    }
1453	
1454	    // If we're a template specialization, we also accept
1455	    // forward-declarations of the underlying template (vector<T>, not
1456	    // vector<int>).
1457	    set<const NamedDecl*> redecls = GetTagRedecls(decl);
1458	    if (const ClassTemplateSpecializationDecl* spec_decl = DynCastFrom(decl)) {
1459	      InsertAllInto(GetTagRedecls(spec_decl->getSpecializedTemplate()),
1460	                    &redecls);
1461	    }
1462	
1463	    // Check if the author forward-declared the class in the same file.
1464	    bool found_earlier_forward_declare_in_same_file = false;
1465	    for (const NamedDecl* redecl : redecls) {
1466	      // In case of something like "typedef struct Manager Manager", the
1467	      // redeclaration and the type will have the same location.
1468	      if (GetLocation(redecl) == use_loc ||
1469	          IsBeforeInSameFile(redecl, use_loc)) {
1470	        found_earlier_forward_declare_in_same_file = true;
1471	        break;
1472	      }
1473	    }
1474	    if (!found_earlier_forward_declare_in_same_file)
1475	      return false;
1476	
1477	    // Check if the the author is not #including the file with the
1478	    // definition. Note if there's no definition anywhere, we
1479	    // say the author does not want the full type (which is a good
1480	    // thing, since there isn't one!)
1481	    if (const NamedDecl* dfn = GetTagDefinition(decl)) {
1482	      if (IsBeforeInSameFile(dfn, use_loc))
1483	        return false;
1484	      const IwyuFileInfo* use_file =
1485	          preprocessor_info().FileInfoFor(GetFileEntry(use_loc));
1486	      if (!use_file)  // Not sure whether this is possible.
1487	        return true;
1488	      if (IsDirectlyIncluded(dfn, *use_file))
1489	        return false;
1490	    }
1491	
1492	    // OK, looks like the author has stated they don't want the fulll type.
1493	    return true;
1494	  }
1495	
1496	  // ast_node is the node for the autocast CastExpr.  We use it to get
1497	  // the parent CallExpr to figure out what function is being called.
1498	  set<const Type*> GetProvidedTypesForAutocast(const ASTNode* ast_node) const {
1499	    while (ast_node && !ast_node->IsA<CallExpr>())
1500	      ast_node = ast_node->parent();
1501	    CHECK_(ast_node && "Should only check Autocast if under a CallExpr");
1502	    const CallExpr* call_expr = ast_node->GetAs<CallExpr>();
1503	    const FunctionDecl* fn_decl = call_expr->getDirectCallee();
1504	    if (!fn_decl)     // TODO(csilvers): what to do for fn ptrs and the like?
1505	      return set<const Type*>();
1506	
1507	    if (const auto* method = dyn_cast<CXXMethodDecl>(fn_decl))
1508	      fn_decl = GetFromLeastDerived(method);
1509	
1510	    // Collect the non-explicit, one-arg constructor ('autocast') types.
1511	    set<const Type*> autocast_types;
1512	    for (FunctionDecl::param_const_iterator param = fn_decl->param_begin();
1513	         param != fn_decl->param_end(); ++param) {
1514	      const Type* param_type = GetTypeOf(*param);
1515	      if (HasImplicitConversionConstructor(param_type)) {
1516	        const Type* deref_param_type =
1517	            RemovePointersAndReferencesAsWritten(param_type);
1518	        autocast_types.insert(Desugar(deref_param_type));
1519	      }
1520	    }
1521	
1522	    // Now look at all the function decls that are visible from the
1523	    // call-location.  A type component is considered as provided if *any*
1524	    // of the function decls provides it.
1525	    set<const Type*> retval;
1526	    for (FunctionDecl::redecl_iterator fn_redecl = fn_decl->redecls_begin();
1527	         fn_redecl != fn_decl->redecls_end(); ++fn_redecl) {
1528	      // Ignore function-decls that we can't see from the use-location.
1529	      if (!preprocessor_info().FileTransitivelyIncludes(
1530	              GetFileEntry(call_expr), GetFileEntry(*fn_redecl))) {
1531	        continue;
1532	      }
1533	      if (fn_redecl->isThisDeclarationADefinition() && !IsInHeader(*fn_redecl))
1534	        continue;
1535	      for (const Type* type : autocast_types) {
1536	        const set<const Type*> components =
1537	            GetProvidedTypes(type, GetLocation(*fn_redecl));
1538	        retval.insert(components.begin(), components.end());
1539	      }
1540	    }
1541	
1542	    return retval;
1543	  }
1544	
1545	  set<const Type*> GetProvidedTypesForFnReturn(const FunctionDecl* decl) const {
1546	    const FunctionDecl* providing_decl = decl;
1547	    if (const auto* method = dyn_cast<CXXMethodDecl>(decl))
1548	      providing_decl = GetFromLeastDerived(method);
1549	    const Type* return_type = providing_decl->getReturnType().getTypePtr();
1550	    return GetProvidedTypes(return_type, GetLocation(providing_decl));
1551	  }
