1554	  // Checkers, that tell iwyu_output about uses of symbols.
1555	  // We let, but don't require, subclasses to override these.
1556	
1557	  // The comment, if not nullptr, is extra text that is included along with
1558	  // the warning message that iwyu emits. The extra use flags is optional
1559	  // info that can be assigned to the use (see the UF_* constants)
1560	  virtual void ReportDeclUse(SourceLocation used_loc,
